   244→func handleQuery(ctx context.Context, raw query.QueryDataRequest, b QueryAPIBuilder, httpreq *http.Request, responder responderWrapper, connectLogger log.Logger) (*backend.QueryDataResponse, error) {
   245→	var jsonQueries = make([]*simplejson.Json, 0, len(raw.Queries))
   246→	for _, query := range raw.Queries {
   247→		dsRef, err := getValidDataSourceRef(ctx, query.Datasource, query.DatasourceID, b.legacyDatasourceLookup)
   248→		if err != nil {
   249→			connectLogger.Error("error getting valid datasource ref", err)
   250→		}
   251→		if dsRef != nil {
   252→			query.Datasource = dsRef
   253→		}
   254→
   255→		jsonBytes, err := json.Marshal(query)
   256→		if err != nil {
   257→			connectLogger.Error("error marshalling", err)
   258→		}
   259→
   260→		sjQuery, _ := simplejson.NewJson(jsonBytes)
   261→		if err != nil {
   262→			connectLogger.Error("error unmarshalling", err)
   263→		}
   264→
   265→		jsonQueries = append(jsonQueries, sjQuery)
   266→	}
   267→
   268→	mReq := dtos.MetricRequest{
   269→		From:    raw.From,
   270→		To:      raw.To,
   271→		Queries: jsonQueries,
   272→	}
   273→
   274→	cache := &MyCacheService{
   275→		legacy: b.legacyDatasourceLookup,
   276→	}
   277→
   278→	headers := ExtractKnownHeaders(httpreq.Header)
   279→
   280→	instance, err := b.instanceProvider.GetInstance(ctx, connectLogger, headers)
   281→	if err != nil {
   282→		connectLogger.Error("failed to get instance configuration settings", "err", err)
   283→		responder.Error(err)
   284→		return nil, err
   285→	}
   286→
   287→	instanceConfig := instance.GetSettings()
   288→
   289→	dsQuerierLoggerWithSlug := instance.GetLogger()
   290→
   291→	qsDsClientBuilder := dsquerierclient.NewQsDatasourceClientBuilderWithInstance(
   292→		instance,
   293→		ctx,
   294→		dsQuerierLoggerWithSlug,
   295→	)
   296→
   297→	exprService := expr.ProvideService(
   298→		&setting.Cfg{
   299→			ExpressionsEnabled:            instanceConfig.ExpressionsEnabled,
   300→			SQLExpressionCellLimit:        instanceConfig.SQLExpressionCellLimit,
   301→			SQLExpressionOutputCellLimit:  instanceConfig.SQLExpressionOutputCellLimit,
   302→			SQLExpressionTimeout:          instanceConfig.SQLExpressionTimeout,
   303→			SQLExpressionQueryLengthLimit: instanceConfig.SQLExpressionQueryLengthLimit,
   304→		},
   305→		nil,
   306→		nil,
   307→		instanceConfig.FeatureToggles,
   308→		nil,
   309→		b.tracer,
   310→		qsDsClientBuilder,
   311→	)
   312→
   313→	qdr, err := service.QueryData(ctx, dsQuerierLoggerWithSlug, cache, exprService, mReq, qsDsClientBuilder, headers)
   314→
   315→	// tell the `instance` structure that it can now report
   316→	// metrics that are only reported once during a request
   317→	instance.ReportMetrics()
   318→
   319→	if err != nil {
   320→		return qdr, err
   321→	}
   322→
   323→	return qdr, nil
   324→}
   325→
   326→type responderWrapper struct {
   327→	wrapped    rest.Responder
   328→	onObjectFn func(statusCode *int, obj runtime.Object)
   329→	onErrorFn  func(err error)
   330→}
   331→
   332→func newResponderWrapper(responder rest.Responder, onObjectFn func(statusCode *int, obj runtime.Object), onErrorFn func(err error)) *responderWrapper {
   333→	return &responderWrapper{
   334→		wrapped:    responder,
   335→		onObjectFn: onObjectFn,
   336→		onErrorFn:  onErrorFn,
   337→	}
   338→}
   339→
   340→func (r responderWrapper) Object(statusCode int, obj runtime.Object) {
   341→	if r.onObjectFn != nil {
   342→		r.onObjectFn(&statusCode, obj)
   343→	}
   344→
   345→	r.wrapped.Object(statusCode, obj)
   346→}
   347→
   348→func (r responderWrapper) Error(err error) {
   349→	if r.onErrorFn != nil {
   350→		r.onErrorFn(err)
   351→	}
   352→
   353→	r.wrapped.Error(err)
   354→}
   355→
   356→func logEmptyRefids(queries []v0alpha1.DataQuery, logger log.Logger) {
   357→	emptyCount := 0
   358→
   359→	for _, q := range queries {
   360→		if q.RefID == "" {
   361→			emptyCount += 1
   362→		}
   363→	}
   364→
   365→	if emptyCount > 0 {
   366→		logger.Info("empty refid found", "empty_count", emptyCount, "query_count", len(queries))
   367→	}
   368→}
   369→
   370→func mergeHeaders(main http.Header, extra http.Header, l log.Logger) {
   371→	for headerName, extraValues := range extra {
   372→		mainValues := main.Values(headerName)
   373→		for _, extraV := range extraValues {
   374→			if !slices.Contains(mainValues, extraV) {
   375→				main.Add(headerName, extraV)
   376→			} else {
   377→				l.Warn("skipped duplicate response header", "header", headerName, "value", extraV)
   378→			}
   379→		}
   380→	}
   381→}
   382→
   383→/*
   384→most queries are stored like this:
   385→
   386→	{
   387→		datasource: {
   388→			uid: "123",
   389→			type: "cool-ds",
   390→		}
   391→	}
   392→
   393→but sometimes queries are stored like:
   394→
   395→	{
   396→		datasourceUid: "123",
   397→		datasource: {
   398→			type: "cool-ds",
   399→		}
   400→	}
   401→
   402→this sets the second case to match the first and looks up missing types
   403→*/
   404→func getValidDataSourceRef(ctx context.Context, ds *v0alpha1.DataSourceRef, id int64, legacyDatasourceLookup ds_service.LegacyDataSourceLookup) (*v0alpha1.DataSourceRef, error) {
   405→	if ds == nil {
   406→		if id == 0 {
   407→			return nil, fmt.Errorf("missing datasource reference or id")
   408→		}
   409→		if legacyDatasourceLookup == nil {
   410→			return nil, fmt.Errorf("legacy datasource lookup unsupported (id:%d)", id)
   411→		}
   412→		return legacyDatasourceLookup.GetDataSourceFromDeprecatedFields(ctx, "", id)
   413→	}
   414→
   415→	// we need to special-case the "grafana" data source
   416→	if ds.UID == "grafana" {
   417→		return &v0alpha1.DataSourceRef{
   418→			// it does not really matter what `type` we set here,
   419→			// we will always detect this case by `uid` later.
   420→			// here we go with what the data source's plugin.json says.
   421→			Type: "grafana",
   422→			UID:  "grafana",
   423→		}, nil
   424→	}
   425→
   426→	if ds.Type == "" {
   427→		if ds.UID == "" {
   428→			return nil, fmt.Errorf("missing name/uid in data source reference")
   429→		}
   430→		if expr.IsDataSource(ds.UID) {
   431→			return ds, nil
   432→		}
   433→		if legacyDatasourceLookup == nil {
   434→			return nil, fmt.Errorf("legacy datasource lookup unsupported (name:%s)", ds.UID)
   435→		}
   436→		return legacyDatasourceLookup.GetDataSourceFromDeprecatedFields(ctx, ds.UID, 0)
   437→	}
   438→
   439→	if ds.UID == "" && expr.IsDataSource(ds.Type) {
   440→		ds.UID = ds.Type
   441→		return ds, nil
   442→	}
   443→
   444→	return ds, nil
   445→}
