   125→		ctx, span := b.tracer.Start(httpreq.Context(), "QueryService.Query")
   126→		defer span.End()
   127→		ctx = request.WithNamespace(ctx, request.NamespaceValue(connectCtx))
   128→		traceId := span.SpanContext().TraceID()
   129→		connectLogger := b.log.New("traceId", traceId.String(), "rule_uid", httpreq.Header.Get("X-Rule-Uid"))
   130→		responder := newResponderWrapper(incomingResponder,
   131→			func(statusCode *int, obj runtime.Object) {
   132→				if *statusCode/100 == 4 {
   133→					span.SetStatus(codes.Error, strconv.Itoa(*statusCode))
   134→				}
   135→
   136→				if *statusCode >= 500 {
   137→					o, ok := obj.(*query.QueryDataResponse)
   138→					if ok && o.Responses != nil {
   139→						for refId, response := range o.Responses {
   140→							if response.ErrorSource == backend.ErrorSourceDownstream {
   141→								*statusCode = http.StatusBadRequest //force this to be a 400 since it's downstream
   142→								span.SetStatus(codes.Error, strconv.Itoa(*statusCode))
   143→								span.SetAttributes(attribute.String("error.source", "downstream"))
   144→								break
   145→							} else if response.Error != nil {
   146→								connectLogger.Debug("500 error without downstream error source", "error", response.Error, "errorSource", response.ErrorSource, "refId", refId)
   147→								span.SetStatus(codes.Error, "500 error without downstream error source")
   148→							} else {
   149→								span.SetStatus(codes.Error, "500 error without downstream error source and no Error message")
   150→								span.SetAttributes(attribute.String("error.ref_id", refId))
   151→							}
   152→						}
   153→					}
   154→				}
   155→				connectLogger.Debug("responder sending status code", "statusCode", statusCode)
   156→			},
   157→
   158→			func(err error) {
   159→				connectLogger.Error("error caught in handler", "err", err)
   160→				span.SetStatus(codes.Error, "query error")
   161→
   162→				if err == nil {
   163→					return
   164→				}
   165→
   166→				span.RecordError(err)
   167→			})
   168→
   169→		raw := &query.QueryDataRequest{}
