   340→func (r responderWrapper) Object(statusCode int, obj runtime.Object) {
   341→	if r.onObjectFn != nil {
   342→		r.onObjectFn(&statusCode, obj)
   343→	}
   344→
   345→	r.wrapped.Object(statusCode, obj)
