   370→func mergeHeaders(main http.Header, extra http.Header, l log.Logger) {
   371→	for headerName, extraValues := range extra {
   372→		mainValues := main.Values(headerName)
   373→		for _, extraV := range extraValues {
   374→			if !slices.Contains(mainValues, extraV) {
   375→				main.Add(headerName, extraV)
   376→			} else {
   377→				l.Warn("skipped duplicate response header", "header", headerName, "value", extraV)
   378→			}
   379→		}
   380→	}
